import React from 'react';
import '../App.css';
import {
  Container, Row, Col,
  ButtonGroup, ButtonToolbar, Button,
  InputGroup, FormControl,
  Navbar, Nav, Form,
  Modal,

} from 'react-bootstrap';

import Clock from 'react-digital-clock';
import DatePicker from 'react-date-picker';

import JobTable from './JobTable';
import { DataContext } from '../data-context';
import { Doughnut } from 'react-chartjs-2';
import { JobForm } from '../forms/JobForm';
import { WorkForm } from '../forms/WorkForm';
import JobSummaryReport from './JobSummaryReport';
import moment from 'moment'; // https://momentjs.com/
// https://github.com/jerairrest/react-chartjs-2
// https://www.chartjs.org/docs/latest/charts/doughnut.html
const config = require('../config.js');

const util = require('../util.js');

export default class Dashboard extends React.Component {

  static contextType = DataContext;

  constructor(...args) {
    super(...args);
    console.log("Dashboard Context:", this.context);
    this.state = {
      // ...this.context,
      // data: this.context.data,
      showJobForm: false,
      showWorkForm: false,
      showReport: false,
      showDatePickerForm: false,
      // showJobForm: true,
      fromDate: new Date(),
      toDate: new Date(),

    };
  }

  setShowJobForm = (show) => this.setState({ showJobForm: show });
  setShowWorkForm = (show) => this.setState({ showWorkForm: show });
  setDatePickerForm = (show) => this.setState({ showDatePickerForm: show });
  setShowReport = (show) => this.setState({ showReport: show });
  handleJobClick = (event, job) => {
    console.log('handleJobClick', event, job)
    this.setState({
      showJobForm: true,
      showWorkForm: false,
      showReport: false,
      createMachineJob: false,
      theJob: job,

    });
  }

  handleWorkClick = (event, job) => {
    console.log('handleJobClick', event, job)
    this.setState({
      showJobForm: false,
      showWorkForm: true,
      createMachineJob: false,
      theJob: job
    });
  }

  handleViewWorkClick = (event, job) => {
    console.log('handleJobClick', event, job)
    this.setState({
      showJobForm: false,
      showWorkForm: true,
      createMachineJob: false,
      theJob: job
    });
  }


  handlePrepareReport = (e) => {
    // console.log('handlePrepareReport:', this.state.showDatePickerForm)
    // this.setState({ showDatePickerForm: true })
    this.setState({ showReport: true })
  }

  handleCreateMachineJob = (e) => {
    this.setState({
      showJobForm: true,
      createMachineJob: true,
      theJob: { state: 0 }
    })
  }


  handleCloseWorkForm = (reload = false) => {
    if (reload) {
      // console.log("Reload parts....", reload)
      util.fetchJobs()
        .then(res =>
          this.setState({
            jobs: res.data,
            showWorkForm: false
          })
        )
    } else {
      this.setState({
        showWorkForm: false
      })
    }
  }

  handleCloseJobForm = (reload = false) => {
    if (reload) {
      // console.log("Reload parts....", reload)
      util.fetchJobs()
        .then(res =>
          this.setState({
            jobs: res.data,
            showJobForm: false,
            createMachineJob: false
          })
        )
    } else {
      this.setState({
        showJobForm: false,
        createMachineJob: false
      })
    }
  }

  // maybe used for general job
  __handleCreateGeneralJob = (e) => {
    this.setState({
      showJobForm: true,
      createGeneralJob: true
    })
  }

  handleFromDateChange = (date) => this.setState({ fromDate: date });
  handleToDateChange = (date) => this.setState({ toDate: date });


  UNSAFE_componentWillMount() {
    console.log('UNSAFE_componentWillMount')

    util.fetchJobs()
      .then(res =>
        this.setState({
          jobs: res.data
        })
      )

    return;
    let data = this.state.data;
    data['jobs'] = util.fetchJobs();
    this.context.data = data['jobs']
    console.log("data['jobs']", data['jobs'])
    this.setState({ data: data });
    this.setState({ jobs: data['jobs'] });
    // document.addEventListener("keydown", this._handleKeyDown);
  }

  render() {
    // let data = this.context.data;
    // let data = this.state.data;
    let jobs = this.state.jobs;

    // Sample Chart
    const chartData = {
      labels: ['Backlog', 'WIP', 'Done'],
      datasets: [{
        data: [300, 50, 100],
        backgroundColor: ['#FF4242', '#4242FF', '#42FF42'],
        hoverBackgroundColor: ['#FF0000', '#0000FF', '#00FF00'],
        borderWidth: [1, 1, 1]
      }]
    };

    const chartOptions = {
      legend: {
        display: false,
      }
    };

    const jobs0 = [];
    const jobs1 = [];
    const jobs2 = [];
    const jobs3 = [];
    // console.log(jobs);
    // if (typeof (data) === 'array')
    //   console.log("data", data)

    if (jobs !== undefined && Promise.resolve(jobs) !== jobs) {
      console.log('jobs.data', jobs)
      jobs.forEach((v, i) => {
        // console.log('v.state', v.state)

        switch (v.state) {
          case 0:
            jobs0.push(v);
            break;
          case 1:
            jobs1.push(v);
            break;
          case 2:
            jobs2.push(v);
            break;
          case 3:
            jobs3.push(v);
            break;
          // default:
          // code block
        }
      });
    }

    if (this.state.showReport) {
      return (
        <DataContext.Provider value={this.context}>
          <JobSummaryReport
            startDate={moment(this.state.fromDate).format('YYYY-MM-DD')}
            // endDate={moment(this.state.endDate).format('YYYY-MM-DD')} 
            endDate={moment(this.state.fromDate).format('YYYY-MM-DD')}
            onClose={() => this.setShowReport(false)} />
        </DataContext.Provider>
      )

    } else {
      return (
        <>
          <DataContext.Provider value={this.context}>
            <Navbar bg="dark" variant="dark" fixed="top">
              <Navbar.Brand href="#home">
                HLT Repair
            </Navbar.Brand>
              <Nav className="mr-auto">
                <Nav.Link href="#users">Users</Nav.Link>
                <Nav.Link href="#help">Help</Nav.Link>
              </Nav>
              <Nav className="mr-auto">
                <Clock />
              </Nav>
              <Form inline>
                <div style={{ backgroundColor: '#ffffff' }}>
                  <DatePicker
                    format="dd/MM/y"
                    onChange={this.handleFromDateChange}
                    value={this.state.fromDate} />
                </div>
                <Button variant="outline-info" onClick={this.handlePrepareReport}>Report</Button>
                <Button variant='danger' onClick={this.handleCreateMachineJob}>Machine Repair</Button>
              </Form>
            </Navbar>

            <Container fluid style={{ marginTop: '40pt' }}>
              <Row className="db-top">
                <Col lg={4}>
                  <JobTable
                    backlog
                    title="Backlog"
                    data={jobs1}
                    handleJobClick={this.handleJobClick}
                  />
                </Col>
                <Col lg={4}>
                  <JobTable
                    wip
                    title="WIP"
                    data={jobs2}
                    handleJobClick={this.handleWorkClick}
                  />
                </Col>
                <Col lg={4}>
                  <JobTable
                    done
                    title="Done"
                    data={jobs3}
                    handleJobClick={this.handleViewWorkClick}
                  />
                </Col>
              </Row>
              {/* <Row>
              <Col lg={3} style={{ verticalAlign: 'text-top' }}>
                <Row style={{ height: 240 }}>
                  <Doughnut data={chartData} options={chartOptions} />
                </Row>
                <Row style={{ alignContent: 'center' }}>
                  <Button size="lg" variant='danger' block onClick={this.handleCreateMachineJob}>Machine Repair</Button>
                </Row>
              </Col>
              <Col>
              </Col>
            </Row> */}
            </Container>

            <Modal
              show={this.state.showDatePickerForm}
              onHide={() => this.setDatePickerForm(false)}
              size="lg"
              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>เลือกช่วงเวลา</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                From:
              <DatePicker
                  format="dd/MM/y"
                  onChange={this.handleFromDateChange}
                  value={this.state.fromDate} />
                To:
              <DatePicker
                  format="dd/MM/y"
                  onChange={this.handleToDateChange}
                  value={this.state.toDate} />
              </Modal.Body>
              <Modal.Footer>
              </Modal.Footer>
            </Modal>

            <Modal
              show={this.state.showJobForm}
              onHide={() => this.setShowJobForm(false)}
              size="md"
              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>แจ้งซ่อมเครื่องจักร</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <JobForm
                  // viewJob={false}
                  // createMachineJob={this.state.createMachineJob}
                  // createGeneralJob={this.state.createGeneralJob}
                  handleClose={this.handleCloseJobForm}
                  data={this.state.theJob} />
              </Modal.Body>
              <Modal.Footer>
                _id {this.state.theJob && <span>{this.state.theJob._id} state: {this.state.theJob.state}</span>}
              </Modal.Footer>
            </Modal>

            <Modal
              show={this.state.showWorkForm}
              onHide={() => this.setShowWorkForm(false)}
              size="lg"
              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>งานซ่อมเครื่องจักร</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <WorkForm
                  handleClose={this.handleCloseWorkForm}
                  data={this.state.theJob} />
              </Modal.Body>
              <Modal.Footer>
                _id {this.state.theJob && <span>{this.state.theJob._id} state: {this.state.theJob.state}</span>}
              </Modal.Footer>
            </Modal >





          </DataContext.Provider>
        </>
      );
    }
  }


}
