export async function fetchJobsByRange(startDate,endDate) {
    // let url = config.apiUrl + 'job/range/' + q;

    let url = `${config.apiUrl}job/range/${startDate}/${endDate}`;

    const response = await fetch(url,
        {
            // signal: this.abortController.signal,
            method: 'GET',
            headers: defaultHeaders
        });
    return response.json();
}


export async function saveJob(job) {
    let url = config.apiUrl + 'job';
    const response = await fetch(url,
        {
            method: 'POST',
            headers: defaultHeaders,
            body: JSON.stringify(job)
        }
    );
    return response.json();
}

export async function updateJob(job) {
    let url = config.apiUrl + 'job';
    const response = await fetch(url,
        {
            method: 'PUT',
            headers: defaultHeaders,
            body: JSON.stringify(job)
        }
    );
    return response.json();
}

export async function fetchJobs(q = '', page = 1, status = 0) {
    // if page === 0, view all
    let viewAll = (page === 0)

    // let skip = viewAll ? 0 : (page - 1) * this.state.itemsPerPage;
    // let limit = viewAll ? 0 : this.state.itemsPerPage;

    // Use of ReactDataGrid, just get all
    let skip = 0;
    let limit = 0;
    // limit = config.defaultPartRowLimit;
    // limit = 20; // DEBUG

    // console.log("fetchJobs", viewAll, skip, limit);
    let url;
    if (q !== '' && q !== null) {
        url = config.apiUrl + 'job/search/' + q;
    } else {
        // url = config.apiUrl + 'part?skip=' + skip + '&limit=' + limit;
        // url = config.apiUrl + 'part';
        let options = {
            skip: skip,
            limit: limit,
            status: status
        };
        url = withQuery(config.apiUrl + 'job', options);
    }

    url = config.apiUrl + 'job';
    console.log('fetchJobs', url);

    const response = await fetch(url,
        {
            // signal: this.abortController.signal,
            method: 'GET',
            headers: defaultHeaders
        });

    // console.log(response.json());
    return response.json();

}

